import '../Styles/TableStyles.css';
import { Component } from 'preact';
import Button from 'react-bootstrap/Button';
import Table from 'react-bootstrap/Table';
import Pagination from 'react-js-pagination';
import Checkbox from "@material-ui/core/Checkbox";
import FormControlLabel from '@material-ui/core/FormControlLabel';

class TableComponent extends Component {

  constructor(props){
    super(props)
    this.state = {
      activePage : 1, //pagina activa inicial en pagination
      itemsCountPerPage:1000, //items por pagina en pagination
      tableColumns:[], //columnas de tabla
      tableRows:[], //filas de tabla
      data:[], //data total en tabla
    }
    this.mount_Table = this.mount_Table.bind(this);
    this.update_Table = this.update_Table.bind(this);
    this.highlightPoints = this.highlightPoints.bind(this);
  }

  //se invoca antes de renderizar cuando se reciben nuevas propiedades o estados
  componentWillReceiveProps(nextProps) {
      this.update_Table(nextProps);
  }

  /*
  * Método para resaltar puntos (check button)
  */
  highlightPoints(item){
    var highlighted_data= this.props.highlighted_data;
    var filtered_highlighted_data;
    if(highlighted_data.includes(item)){
      highlighted_data = highlighted_data.filter((i) => i !== item)
    }
    else {
      highlighted_data.push(item);
    }
    this.props.callback_highlighted_data(highlighted_data);
  }

  /*
  * Dibujo las columnas de la tabla
  */
  mount_Table(props){
    var tableColumns = [];

    var arrColumns = ['Ref','Category','SubCategory','SiO2','TiO2','V2O3','Al2O3','Cr2O3','FeO','Fe2O3','MnO','MgO','NiO',
    'ZnO','Cr','Ti','Al','Fe3','Fe2','Mn','Mg','Ni','Zn'];

    //Completo las columnas
    tableColumns.push(<th>#</th>);
    tableColumns.push(<th>highlight</th>);
    {Array.from({ length: arrColumns.length }).map((_, index) => (
          tableColumns.push(<th key={index} id={arrColumns[index]}>{arrColumns[index]}</th>)))}
    this.setState({tableColumns:tableColumns});
  }

  /*
  * Dibujo las filas de la tabla
  */
  update_Table(props){
    this.mount_Table(props);
    const arr = [];
    var data = props.data;
    var tableRows = [];
    var scaleColor = d3.scaleOrdinal()
      .domain(["Alaskan ultramafic","Alkali/Lamprophyres","Basalt","Komatiite","Laterite","Layered intrusion","Metamorphic","Ophiolite","Xenoliths"])
      .range(["#7986cb","#f06292", "#ff8a65", "#ffb74d", "#fff176", "#aed581", "#4db6ac","#64b5f6", "#ba68c8"])

    if(props.selected_data.length>0){ //Si hay elemento seleccionados en las otras vistas
      for (let j = 0; j < props.selected_data.length; j++) {
          arr.push([
            +data[props.selected_data[j]].i,
            data[props.selected_data[j]].Ref,
            data[props.selected_data[j]].Category1,
  					data[props.selected_data[j]].Category2,
  				  +data[props.selected_data[j]].SiO2,
  					+data[props.selected_data[j]].TiO2,
  					+data[props.selected_data[j]].V2O3,
  					+data[props.selected_data[j]].Al2O3,
  					+data[props.selected_data[j]].Cr2O3,
  					+data[props.selected_data[j]].FeO,
  					+data[props.selected_data[j]].Fe2O3,
  					+data[props.selected_data[j]].MnO,
  					+data[props.selected_data[j]].MgO,
  					+data[props.selected_data[j]].NiO,
  				  +data[props.selected_data[j]].ZnO,
  					+data[props.selected_data[j]].Cr,
  					+data[props.selected_data[j]].Ti,
  					+data[props.selected_data[j]].Al,
  					+data[props.selected_data[j]].Fe3,
  					+data[props.selected_data[j]].Fe2,
  					+data[props.selected_data[j]].Mn,
  					+data[props.selected_data[j]].Mg,
  					+data[props.selected_data[j]].Ni,
  					+data[props.selected_data[j]].Zn,
          ]);
      }
    }

    this.setState({data:arr});

    //Completo las filas
    var row = [];
    var end = this.state.itemsCountPerPage;
    if(arr.length<end) end = arr.length;
    for(let i = 0; i < end; i++){
      row.push(<td>{arr[i][0]}</td>);
      row.push(<td> <Checkbox checked={props.highlighted_data.includes(arr[i][0])} onClick={() => this.highlightPoints(arr[i][0])} /></td>);
      for(let j = 1; j< arr[i].length;j++){
        if(j==2){ //Category (escribo la categoria con el color correspondiente)
          row.push(<td key={i+""+j} style={{backgroundColor:scaleColor(arr[i][j]), color:"#FFFFFF"}}> {arr[i][j]}</td>);
        }
        else {
          row.push(<td key={i+""+j}> {arr[i][j]}</td>);
        }
      }

      tableRows.push(<tr key={"f"+i}>{row}</tr>);
      row = [];
    }

    this.setState({tableRows:tableRows});

    //Dibujo los gráficos de las columnas
    var arrColumns = ['SiO2','TiO2','V2O3','Al2O3','Cr2O3','FeO','Fe2O3','MnO','MgO','NiO',
    'ZnO','Cr','Ti','Al','Fe3','Fe2','Mn','Mg','Ni','Zn'];
    //Actualizar los boxplots de columnas!!
    var dd = [];

    for(let i = 0; i<arrColumns.length; i++){
      // append the svg object to the body of the page
      dd = [];
      for(let j = 0; j<arr.length;j++){
          dd.push(arr[j][i+4]);
      }

      d3.select("#"+arrColumns[i]).selectAll("*").remove()

      if(dd.length>0){
        var min = d3.min(dd);
        var max = d3.max(dd);

        var margin = { top: 10, right: 15, bottom: 15, left: 15 },
          width = 120 - margin.left - margin.right,
          height = 60 - margin.top - margin.bottom;

        var dataDomain = [0, 100];

        var x = d3.scaleLinear()
            .domain(dataDomain)
            .rangeRound([0, width])
            // make x domain start and end nice
            .nice();

        var numBins = 100;
        var thresholds = x.ticks(numBins);

        // add the data domain bounds to the thresholds
        //thresholds.concat(dataDomain)
        //thresholds.sort(d3.ascending);

        var bins = d3.histogram()
            .domain(x.domain())
            .thresholds(thresholds)
            (dd);

        // the value is the height
        bins = bins.map(function(d) {
            d.value = d.length;
            return d;
        })

        var y = d3.scaleLinear()
            .domain([0, d3.max(bins, function(d) { return d.value; })])
            .range([height, 0]);

        var svg = d3.select("#"+arrColumns[i])
            .append("svg")
            .attr("width", width + margin.left + margin.right)
            .attr("height", height + margin.top + margin.bottom)
            .append("g")
            .attr("transform", "translate(" + margin.left + "," + margin.top + ")");

        var bar = svg.selectAll(".bar")
            .data(bins)
            .enter().append("g")
                .attr("class", "bar")
                .attr("transform", function(d) { return "translate(" + x(d.x0) + "," + y(d.value) + ")";});
        bar.append("rect")
            .attr("x", 0)
            .style("fill", function(d,i){/*
              if(props.highlighted_data.includes(arr[i][0]))
                return scaleColor(arr[i][2]);
              else {
                return "#000000";
              } */
              return "#000000";
            })
            .attr("width", function(d) { return (x(d.x1) - x(d.x0) ); })
            .attr("height", function(d) { return height - (y(d.value)); })


        svg.append("g")
            .attr("class", "axis axis--x axisTable")
            .attr("transform", "translate(0," + height + ")")
            .call(d3.axisBottom(x).ticks(2).tickValues([0,100]).tickFormat(d3.format(".2f")).tickSizeInner(3).tickSizeOuter(0));
      }
    }
  }

  /*
  * Modifico las filas visibles en la tabla al seleccionar una pagina nueva del pagination
  */
  handlePageChange(pageNumber) {
    var scaleColor = d3.scaleOrdinal()
      .domain(["Alaskan ultramafic","Alkali/lamprophyres","Basalt","Komatiite","Laterite","Layered intrusion","Metamorphic","Ophiolite","Xenoliths"])
      .range(["#4D69DC","#9e0142", "#e95c47", "#fdbf6f", "#ffffbe", "#bfe5a0", "#54aead", "#5e4fa2", "#DC4DD8"])

    //Completo las filas
    var row = [];
    var arr = this.state.data;
    var tableRows = [];

    var end = pageNumber*this.state.itemsCountPerPage;
    if(arr.length<end) end = arr.length;
    for(let i = (pageNumber-1)*this.state.itemsCountPerPage; i < end; i++){

      row.push(<td>{arr[i][0]}</td>);
      row.push(<td> <Checkbox checked={this.props.highlighted_data.includes(arr[i][0])} onClick={() => this.highlightPoints(arr[i][0])} /></td>);
      for(let j = 1; j< arr[i].length;j++){
        if(j==1){ //Category (escribo la categoria con el color correspondiente)
          row.push(<td key={i+""+j} style={{backgroundColor:scaleColor(arr[i][j]), color:"#FFFFFF"}}> {arr[i][j]}</td>);
        }
        else {
          row.push(<td key={i+""+j}> {arr[i][j]}</td>);
        }
      }

      tableRows.push(<tr key={"f"+i}>{row}</tr>);
      row = [];
    }

    this.setState({tableRows:tableRows});
    this.setState({activePage: pageNumber});
  }

  render(){
    return (
      <div class="container-Table">
        <Pagination
            activePage={this.state.activePage}
            itemsCountPerPage={this.state.itemsCountPerPage}
            totalItemsCount={this.state.data.length}
            pageRangeDisplayed={10}
            onChange={this.handlePageChange.bind(this)}
            onClick={console.log("")}
          />
        <div class="table-responsive-md">
          <Table bordered hover>
            <thead>
              <tr>
                {this.state.tableColumns}
              </tr>
            </thead>
            <tbody>
              {this.state.tableRows}
            </tbody>
          </Table>
        </div>
      </div>
    );
  }

}
export default TableComponent;
